1882	[G3.3 — flatness over a local base is local on the source affine]
1883	  \label{lem:gf_flat_base_local_on_source}
1884	  \lean{AlgebraicGeometry.gf_flat_base_local_on_source}
1885	  \uses{lem:mathlib_flat_of_isLocalized_maximal}
1886	  Let \(R\) be a commutative ring, \(B\) an \(R\)-algebra, and \(N\) a \(B\)-module,
1887	  regarded as an \(R\)-module through the scalar tower \(R \to B \to N\). Suppose
1888	  that for every maximal ideal \(\mathfrak q \subset B\) the localization
1889	  \(N_{\mathfrak q}\) is flat over \(R\). Then \(N\) is flat over \(R\).
1890	\end{lemma}
1891	
1892	\begin{proof}
1893	  \uses{lem:mathlib_flat_of_isLocalized_maximal}
1894	  This is the source-locality criterion for flatness over a fixed base ring,
1895	  instantiated with the canonical localizations \(N_{\mathfrak q}\) of \(N\) at the
1896	  maximal ideals \(\mathfrak q\) of \(B\): each \(N_{\mathfrak q}\) is a localized
1897	  module of \(N\) at the prime \(\mathfrak q\) of the source ring \(B\), and the
1898	  hypothesis supplies the required flatness of every \(N_{\mathfrak q}\) over \(R\).
1899	  \Cref{lem:mathlib_flat_of_isLocalized_maximal} then yields that \(N\) is flat over
1900	  \(R\). \emph{(Note: unlike \cref{lem:mathlib_flat_of_localized_maximal}, which
1901	  localizes over the same ring it tests flatness over, here \(N\) is localized at the
1902	  primes of the source ring \(B\) while flatness is tested over the distinct base
1903	  ring \(R\).)}
1904	\end{proof}
