1927	\begin{lemma}\leanok
1928	[B1 — localizing the source ring preserves flatness over the base]
1929	  \label{lem:gf_flat_localizedModule_sameBase}
1930	  \lean{AlgebraicGeometry.gf_flat_localizedModule_sameBase}
1931	  \uses{lem:gf_localizedModule_baseChange_tensor_comm}
1932	  Let \(R \to B \to N\) be a scalar tower in which \(N\) is a \(B\)-module, and let
1933	  \(T \subseteq B\) be a submonoid of the \emph{source} ring \(B\). View \(N\) as an
1934	  \(R\)-module through the tower. If \(N\) is flat over \(R\), then the localized module
1935	  \(\mathrm{LocalizedModule}\,T\,N\) is again flat over \(R\). \emph{(Note: the existing
1936	  Mathlib results \cref{lem:mathlib_flat_localization_preserves} localize over a
1937	  submonoid of the \emph{base} \(R\); here the submonoid lives in the source \(B\) while
1938	  the base \(R\) is untouched, so a separate argument is required.)}
1939	\end{lemma}
1940	
1941	\begin{proof}
1942	  \uses{lem:gf_localizedModule_baseChange_tensor_comm}
1943	  Localization at \(T\) commutes with tensoring against an \(R\)-module: by
1944	  \cref{lem:gf_localizedModule_baseChange_tensor_comm}, for every \(R\)-module \(K\)
1945	  there is a natural isomorphism
1946	  \[
1947	    \mathrm{LocalizedModule}\,T\,(N \otimes_R K)
1948	      \;\cong\; (\mathrm{LocalizedModule}\,T\,N) \otimes_R K,
1949	  \]
1950	  natural in \(K\) (compatible with the maps induced by any \(R\)-linear \(K \to K'\)).
1951	  Flatness of \(N\) over \(R\) means that for every injection \(K \hookrightarrow K'\) of
1952	  \(R\)-modules the induced map \(N \otimes_R K \to N \otimes_R K'\) is injective.
1953	  Localization at the submonoid \(T\) is an exact functor, so it preserves this
1954	  injectivity; transporting along the natural isomorphism turns the result into
1955	  injectivity of
1956	  \((\mathrm{LocalizedModule}\,T\,N) \otimes_R K \to (\mathrm{LocalizedModule}\,T\,N) \otimes_R K'\).
1957	  As this holds for every injection of \(R\)-modules, \(\mathrm{LocalizedModule}\,T\,N\)
1958	  is flat over \(R\).
1959	\end{proof}
